/* ─── TOAST HOOK ─── */
function useToast() {
  const [msg, setMsg] = useState('');
  const [visible, setVisible] = useState(false);
  const show = useCallback((m) => {
    setMsg(m); setVisible(true);
    setTimeout(() => setVisible(false), 4000);
  }, []);
  return { msg, visible, show };
}

