/* ─── CURSOR ─── */
function Cursor() {
  const [pos,setPos]=useState({x:0,y:0});
  const [ring,setRing]=useState({x:0,y:0});
  const [big,setBig]=useState(false);
  const raf=useRef(null);
  const tgt=useRef({x:0,y:0});
  useEffect(()=>{
    const mv=e=>{setPos({x:e.clientX,y:e.clientY});tgt.current={x:e.clientX,y:e.clientY};};
    window.addEventListener('mousemove',mv);
    const tick=()=>{setRing(p=>({x:p.x+(tgt.current.x-p.x)*0.13,y:p.y+(tgt.current.y-p.y)*0.13}));raf.current=requestAnimationFrame(tick);};
    raf.current=requestAnimationFrame(tick);
    return()=>{window.removeEventListener('mousemove',mv);cancelAnimationFrame(raf.current);};
  },[]);
  useEffect(()=>{
    const ov=()=>setBig(true),ot=()=>setBig(false);
    const els=document.querySelectorAll('button,input,textarea,a');
    els.forEach(el=>{el.addEventListener('mouseenter',ov);el.addEventListener('mouseleave',ot);});
    return()=>els.forEach(el=>{el.removeEventListener('mouseenter',ov);el.removeEventListener('mouseleave',ot);});
  });
  return(
    <>
      <div className={`cursor${big?' big':''}`} style={{left:pos.x+'px',top:pos.y+'px'}}/>
      <div className={`cursor-ring${big?' big':''}`} style={{left:ring.x+'px',top:ring.y+'px'}}/>
    </>
  );
}

